const stakeholders = $input.all()[0].json;
const interactions  = $input.all()[1]?.json ?? [];

const stArr = Array.isArray(stakeholders) ? stakeholders : [];
const intArr = Array.isArray(interactions) ? interactions : [];

const today = new Date();

// Agrupar interacciones por stakeholder_id → última interacción
const lastInt = {};
for (const i of intArr) {
  const sid = i.stakeholder_id;
  if (!sid) continue;
  if (!lastInt[sid] || new Date(i.timestamp) > new Date(lastInt[sid].timestamp)) {
    lastInt[sid] = i;
  }
}

const result = [];
for (const sh of stArr) {
  const sid = sh.id;
  const li = lastInt[sid];
  const lastDate = li ? new Date(li.timestamp) : null;
  const dias = lastDate
    ? Math.floor((today - lastDate) / 86400000)
    : 999;
  const resultado = li?.resultado ?? 'neutro';

  let salud, razon;
  if (resultado === 'bloqueo') {
    salud = 'rojo';
    razon = 'Última interacción marcada como bloqueo';
  } else if (resultado === 'negativo') {
    salud = 'rojo';
    razon = 'Última interacción negativa';
  } else if (dias > 30) {
    salud = 'amarillo';
    razon = `Sin contacto hace ${dias} días`;
  } else if (dias > 15) {
    salud = 'amarillo';
    razon = `Sin contacto hace ${dias} días (zona de riesgo)`;
  } else {
    salud = 'verde';
    razon = `Contacto hace ${dias} días, resultado ${resultado}`;
  }

  result.push({
    stakeholder_id: sid,
    salud,
    razon,
    dias_sin_contacto: dias,
    resultado_ultima_interaccion: resultado
  });
}

return result.map(r => ({ json: r }));

const items = $input.all();
const batch = items[0]?.json?.batch ?? [];
const rojos    = batch.filter(i => i.salud === 'rojo').length;
const amarillos = batch.filter(i => i.salud === 'amarillo').length;
const verdes   = batch.filter(i => i.salud === 'verde').length;
return [{ json: { rojos, amarillos, verdes, total: batch.length, alertar: rojos > 0 || amarillos > 5 } }];

const d = $input.first().json;
const fecha = new Date().toLocaleDateString('es-CO', {weekday:'long',day:'numeric',month:'long'});
const msg = `🚨 *Reporte de Salud — ${fecha}*\n\n` +
  `🔴 Rojos: ${d.rojos}\n` +
  `🟡 Amarillos: ${d.amarillos}\n` +
  `🟢 Verdes: ${d.verdes}\n\n` +
  `Total stakeholders analizados: ${d.total}\n\n` +
  `Revisa el dashboard para ver detalles: https://la-falla-df-api-gm.7ubo23.easypanel.host/stakeholder-health/current?salud=rojo`;
return [{ json: { content: msg } }];
